import{_ as t,o as r,c as o,ag as i}from"./chunks/framework.DUvHsH_U.js";const c=JSON.parse('{"title":"Order Placement and Minimum Order Requirements Setup","description":"","frontmatter":{},"headers":[],"relativePath":"orders/order-placement-and-minimum-order-requirements-setup.md","filePath":"orders/order-placement-and-minimum-order-requirements-setup.md","lastUpdated":1777975835000}'),s={name:"orders/order-placement-and-minimum-order-requirements-setup.md"};function l(n,e,a,d,g,u){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="order-placement-and-minimum-order-requirements-setup" tabindex="-1">Order Placement and Minimum Order Requirements Setup <a class="header-anchor" href="#order-placement-and-minimum-order-requirements-setup" aria-label="Permalink to &quot;Order Placement and Minimum Order Requirements Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup allows logged-in customers to place orders successfully from the mobile app. It also controls whether the app blocks checkout until the cart reaches the client&#39;s required minimum order amount.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Open Role Permission Manager</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Role Permission Manager</strong> and open it.</li></ul></li><li><p><strong>Allow customers to create sales orders</strong></p><ul><li>In the <strong>Document Type</strong> field, select <strong>Sales Order</strong>.</li><li>Find the row for the <strong>Customer</strong> role.</li><li>If there is no Customer row, add a new row and select <strong>Customer</strong> as the role.</li><li>Check <strong>Read</strong>.</li><li>Check <strong>Write</strong>.</li><li>Check <strong>Create</strong>.</li><li>Click <strong>Update</strong> or <strong>Save</strong>.</li></ul></li><li><p><strong>Allow customers to read sales invoices</strong></p><ul><li>Stay in <strong>Role Permission Manager</strong>.</li><li>In the <strong>Document Type</strong> field, select <strong>Sales Invoice</strong>.</li><li>Find or add the <strong>Customer</strong> role row.</li><li>Check <strong>Read</strong>.</li><li>Click <strong>Update</strong> or <strong>Save</strong>.</li></ul></li><li><p><strong>Allow customers to read payment entries</strong></p><ul><li>Stay in <strong>Role Permission Manager</strong>.</li><li>In the <strong>Document Type</strong> field, select <strong>Payment Entry</strong>.</li><li>Find or add the <strong>Customer</strong> role row.</li><li>Check <strong>Read</strong>.</li><li>Click <strong>Update</strong> or <strong>Save</strong>.</li></ul></li><li><p><strong>Allow customers to manage addresses</strong></p><ul><li>Stay in <strong>Role Permission Manager</strong>.</li><li>In the <strong>Document Type</strong> field, select <strong>Address</strong>.</li><li>Find or add the <strong>Customer</strong> role row.</li><li>Check <strong>Read</strong>.</li><li>Check <strong>Write</strong>.</li><li>Check <strong>Create</strong>.</li><li>Click <strong>Update</strong> or <strong>Save</strong>.</li></ul></li><li><p><strong>Open Mobile E-Commerce Settings</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Mobile E-Commerce Settings</strong> and open it.</li></ul></li><li><p><strong>Set the minimum order amount</strong></p><ul><li>Locate the <strong>Minimum order price</strong> field.</li><li>Enter the minimum cart total required before customers can place an order.</li><li>If the client does not require a minimum order amount, leave the value as <strong>0</strong> or blank according to the site&#39;s setup.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Confirm the logged-in customer has normal order prerequisites</strong></p><ul><li>Go to <strong>Customer List</strong>.</li><li>Open the customer account used for testing.</li><li>Confirm the customer is active.</li><li>Confirm the customer has a valid <strong>Customer Group</strong> if the client uses customer groups.</li><li>Confirm the customer has a valid <strong>Territory</strong>.</li><li>Confirm the selected territory has the warehouse setup required by this client.</li><li>Confirm the customer has a valid selling price list if the client uses customer-specific price lists.</li><li>Save any changes.</li></ul></li><li><p><strong>Confirm the customer has a usable address</strong></p></li></ol><ul><li>Go to <strong>Address List</strong>.</li><li>Open or create the delivery address for the testing customer.</li><li>Confirm the address is linked to the correct customer.</li><li>Confirm the required address fields are filled, especially city and delivery details required by the client&#39;s ERPNext setup.</li><li>Click <strong>Save</strong>.</li></ul><ol start="11"><li><strong>Test the order in the mobile app</strong></li></ol><ul><li>Fully close and reopen the mobile app.</li><li>Log in as the test customer.</li><li>Add products to the cart.</li><li>Open checkout.</li><li>Select or confirm the delivery address.</li><li>If a minimum order amount is configured and the cart total is below it, the app should show a minimum order message and the place order button should be disabled.</li><li>Add more products until the cart reaches the required amount.</li><li>Tap <strong>Place Order</strong>.</li><li>If the setup is correct, the app should show an order success message, clear the cart, and open the new order details screen.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ol><li><p><strong>If the app says the order failed because of Missing Required Fields</strong></p><ul><li>This means this specific client&#39;s ERPNext system has custom mandatory fields on <strong>Sales Order</strong> that the standard mobile app does not support yet.</li><li>Do not try to fix this by changing random permission settings.</li><li>Record the exact missing field message shown during testing.</li><li>Report it to the implementation or app development team so the mobile app can be updated for this client.</li><li>In the mobile app, the tester will usually stay on the checkout screen and see a red error message instead of the success message and order details screen.</li></ul></li><li><p><strong>If the exact error says ModuleNotFoundError: No module named &#39;firebase_admin&#39;</strong></p><ul><li>This has nothing to do with the mobile app checkout screen, customer permissions, or Mobile E-Commerce Settings.</li><li>It is a critical server configuration issue.</li><li>Stop testing immediately.</li><li>Escalate the issue to the backend development team.</li><li>Do not continue changing ERPNext UI settings to solve this error.</li></ul></li><li><p><strong>If the place order button is disabled</strong></p><ul><li>This usually means the cart total is still below the value in <strong>Minimum order price</strong>.</li><li>Open <strong>Mobile E-Commerce Settings</strong>.</li><li>Check the <strong>Minimum order price</strong> value.</li><li>In the mobile app, add more products until the total reaches this amount.</li><li>If the client does not want a minimum cart total, set <strong>Minimum order price</strong> to <strong>0</strong> or blank according to the site&#39;s setup, save, then fully close and reopen the app.</li></ul></li><li><p><strong>If the customer cannot create an order at all</strong></p><ul><li>This usually means the <strong>Customer</strong> role does not have the required Sales Order permissions.</li><li>Open <strong>Role Permission Manager</strong>.</li><li>Select <strong>Sales Order</strong>.</li><li>Confirm the <strong>Customer</strong> role has <strong>Read</strong>, <strong>Write</strong>, and <strong>Create</strong> checked.</li><li>Click <strong>Update</strong> or <strong>Save</strong>, then test again in the mobile app.</li></ul></li></ol>',10)])])}const h=t(s,[["render",l]]);export{c as __pageData,h as default};
